// ============================================================
// App.js — Root React Component
// ============================================================
// Wraps the entire app in:
//   1. BrowserRouter  — enables React Router URL matching
//   2. AuthProvider   — global authentication state
//   3. AppRoutes      — all route definitions
// ============================================================

import React from "react";
import { BrowserRouter } from "react-router-dom";
import { AuthProvider } from "./context/AuthContext";
import AppRoutes from "./routes/AppRoutes";
import "./styles/global.css";  // Import global styles first

function App() {
  return (
    <BrowserRouter>
      {/* AuthProvider wraps everything so all components can access auth state */}
      <AuthProvider>
        <AppRoutes />
      </AuthProvider>
    </BrowserRouter>
  );
}

export default App;
